/**
 * CSV Parser Library
 * A comprehensive TypeScript CSV parser with support for quoted fields,
 * type coercion, and aggregation operations.
 */

interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

interface ParseError {
  row: number;
  message: string;
}

interface CSVResultInterface {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>) => boolean): CSVResultInterface;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<string | number | boolean | null, Array<Record<string, any>>>;
}

/**
 * Represents the result of parsing a CSV string
 */
class CSVResult implements CSVResultInterface {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: ParseError[];

  constructor(
    rows: Array<Record<string, any>>,
    headers: string[],
    errors: ParseError[] = []
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   * Returns a new CSVResult with only matching rows
   */
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum all numeric values in a column
   * Non-numeric values are ignored
   */
  sum(column: string): number {
    let total = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number') {
        total += value;
      }
    }
    return total;
  }

  /**
   * Calculate the average of numeric values in a column
   * Non-numeric values are ignored
   */
  average(column: string): number {
    const values = this.rows
      .map(row => row[column])
      .filter(value => typeof value === 'number') as number[];

    if (values.length === 0) return 0;
    return this.sum(column) / values.length;
  }

  /**
   * Count total number of rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by unique values in a column
   * Returns a Map where keys are column values and values are arrays of matching rows
   */
  groupBy(column: string): Map<string | number | boolean | null, Array<Record<string, any>>> {
    const groups = new Map<string | number | boolean | null, Array<Record<string, any>>>();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }

    return groups;
  }
}

/**
 * Parse a line of CSV into fields
 * Handles quoted fields and escaped quotes
 */
function parseCSVLine(
  line: string,
  delimiter: string = ',',
  quote: string = '"'
): { fields: string[]; error?: string } {
  const fields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (inQuotes) {
      if (char === quote) {
        if (nextChar === quote) {
          // Escaped quote (two consecutive quotes)
          currentField += quote;
          i += 2;
        } else {
          // End of quoted field
          inQuotes = false;
          i++;
        }
      } else {
        currentField += char;
        i++;
      }
    } else {
      if (char === quote) {
        // Start of quoted field
        inQuotes = true;
        i++;
      } else if (char === delimiter) {
        // Field delimiter
        fields.push(currentField);
        currentField = '';
        i++;
      } else {
        currentField += char;
        i++;
      }
    }
  }

  // Add the last field
  fields.push(currentField);

  // Check for unclosed quotes
  if (inQuotes) {
    return { fields, error: 'Unclosed quote in line' };
  }

  return { fields };
}

/**
 * Coerce a string value to its appropriate type
 * Handles: numbers, booleans, null, and strings
 */
function coerceType(value: string): string | number | boolean | null {
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for number
  const num = Number(value);
  if (!isNaN(num) && value.trim() !== '') {
    // Ensure it's actually a valid number string (not just whitespace)
    if (String(num) === String(parseFloat(value))) {
      return num;
    }
  }

  // Return as string
  return value;
}

/**
 * Parse a CSV string into structured data
 * @param input The CSV string to parse
 * @param options Parser configuration
 * @returns A CSVResult object with rows, headers, errors, and utility methods
 */
export function parseCSV(
  input: string,
  options?: CSVOptions
): CSVResult {
  const delimiter = options?.delimiter ?? ',';
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? '\n';

  const errors: ParseError[] = [];

  // Handle empty input
  if (!input || input.trim() === '') {
    return new CSVResult([], [], []);
  }

  // Split into lines
  const lines = input.split(lineSeparator);

  // Handle case where input ends with separator
  if (lines[lines.length - 1] === '') {
    lines.pop();
  }

  if (lines.length === 0) {
    return new CSVResult([], [], []);
  }

  // Parse header line
  const headerLine = lines[0];
  const headerResult = parseCSVLine(headerLine, delimiter, quote);

  if (headerResult.error) {
    errors.push({ row: 0, message: headerResult.error });
  }

  const headers = headerResult.fields.map(field => field.trim());

  // Parse data lines
  const rows: Array<Record<string, any>> = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (line.trim() === '') {
      continue;
    }

    const parseResult = parseCSVLine(line, delimiter, quote);

    if (parseResult.error) {
      errors.push({ row: i, message: parseResult.error });
      continue;
    }

    const fields = parseResult.fields;

    // Check if the number of fields matches headers
    if (fields.length !== headers.length) {
      errors.push({
        row: i,
        message: `Expected ${headers.length} fields, got ${fields.length}`,
      });
      continue;
    }

    // Create row object
    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j++) {
      const rawValue = fields[j].trim();
      row[headers[j]] = coerceType(rawValue);
    }

    rows.push(row);
  }

  return new CSVResult(rows, headers, errors);
}

export type { CSVOptions, ParseError, CSVResultInterface };

/**
 * Comprehensive test suite for CSV Parser
 * Tests all features and edge cases
 */

import { parseCSV } from './csv-parser';

// Simple assertion helper
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${expected}\nActual: ${actual}`
    );
  }
}

function assertDeepEquals(actual: any, expected: any, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

// Test counters
let testsRun = 0;
let testsPassed = 0;

function runTest(name: string, testFn: () => void): void {
  testsRun++;
  try {
    testFn();
    testsPassed++;
    console.log(`✓ ${name}`);
  } catch (error) {
    console.error(`✗ ${name}`);
    console.error(`  ${error instanceof Error ? error.message : String(error)}`);
  }
}

// ============================================================================
// BASIC PARSING TESTS
// ============================================================================

runTest('Basic parsing - simple CSV', () => {
  const csv = 'name,age,city\nAlice,30,New York\nBob,25,London';
  const result = parseCSV(csv);

  assertEquals(result.headers.length, 3, 'Should have 3 headers');
  assertEquals(result.rows.length, 2, 'Should have 2 rows');
  assertEquals(result.rows[0].name, 'Alice', 'First row name should be Alice');
  assertEquals(result.rows[0].age, 30, 'First row age should be 30');
  assertEquals(result.rows[1].city, 'London', 'Second row city should be London');
});

runTest('Basic parsing - single column', () => {
  const csv = 'name\nAlice\nBob\nCharlie';
  const result = parseCSV(csv);

  assertEquals(result.headers.length, 1, 'Should have 1 header');
  assertEquals(result.rows.length, 3, 'Should have 3 rows');
  assertEquals(result.rows[1].name, 'Bob', 'Second row name should be Bob');
});

runTest('Basic parsing - single row', () => {
  const csv = 'name,age\nAlice,30';
  const result = parseCSV(csv);

  assertEquals(result.headers.length, 2, 'Should have 2 headers');
  assertEquals(result.rows.length, 1, 'Should have 1 row');
  assertEquals(result.rows[0].name, 'Alice', 'Row name should be Alice');
});

runTest('Basic parsing - header only (no data rows)', () => {
  const csv = 'name,age,city';
  const result = parseCSV(csv);

  assertEquals(result.headers.length, 3, 'Should have 3 headers');
  assertEquals(result.rows.length, 0, 'Should have 0 data rows');
});

// ============================================================================
// QUOTED FIELDS TESTS
// ============================================================================

runTest('Quoted fields - basic quoted field', () => {
  const csv = 'name,description\nAlice,"A person"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(result.rows[0].description, 'A person', 'Description should be unquoted');
});

runTest('Quoted fields - field with comma inside quotes', () => {
  const csv = 'name,address\nAlice,"123 Main St, New York"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(
    result.rows[0].address,
    '123 Main St, New York',
    'Address should contain comma'
  );
});

runTest('Quoted fields - multiple fields with commas', () => {
  const csv = 'name,address,phone\nAlice,"123 Main St, New York","555-1234, ext 5"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(result.rows[0].address, '123 Main St, New York', 'Address should be correct');
  assertEquals(result.rows[0].phone, '555-1234, ext 5', 'Phone should be correct');
});

runTest('Quoted fields - quoted field with newline (escaped)', () => {
  const csv = 'name,note\nAlice,"Line 1\nLine 2"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(result.rows[0].note, 'Line 1\nLine 2', 'Note should contain newline');
});

// ============================================================================
// ESCAPED QUOTES TESTS
// ============================================================================

runTest('Escaped quotes - two quotes become one', () => {
  const csv = 'name,quote\nAlice,"She said ""hello"""';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(result.rows[0].quote, 'She said "hello"', 'Quote should unescape');
});

runTest('Escaped quotes - multiple escaped quotes', () => {
  const csv = 'text\n"A""B""C"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, 'A"B"C', 'Should have two quotes');
});

runTest('Escaped quotes - quote at start', () => {
  const csv = 'text\n"""quoted"""';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, '"quoted"', 'Should have quotes at start and end');
});

// ============================================================================
// CUSTOM DELIMITERS TESTS
// ============================================================================

runTest('Custom delimiter - semicolon', () => {
  const csv = 'name;age;city\nAlice;30;New York';
  const result = parseCSV(csv, { delimiter: ';' });

  assertEquals(result.headers.length, 3, 'Should have 3 headers');
  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(result.rows[0].city, 'New York', 'City should be New York');
});

runTest('Custom delimiter - tab', () => {
  const csv = 'name\tage\tcity\nAlice\t30\tNew York';
  const result = parseCSV(csv, { delimiter: '\t' });

  assertEquals(result.headers.length, 3, 'Should have 3 headers');
  assertEquals(result.rows[0].age, 30, 'Age should be 30');
});

runTest('Custom delimiter - pipe', () => {
  const csv = 'name|age\nAlice|30';
  const result = parseCSV(csv, { delimiter: '|' });

  assertEquals(result.rows[0].name, 'Alice', 'Name should be Alice');
  assertEquals(result.rows[0].age, 30, 'Age should be 30');
});

runTest('Custom quote character - single quote', () => {
  const csv = "name,city\nAlice,'New York'";
  const result = parseCSV(csv, { quote: "'" });

  assertEquals(result.rows[0].city, 'New York', 'City should be unquoted');
});

runTest('Custom line separator - CRLF', () => {
  const csv = 'name,age\r\nAlice,30\r\nBob,25';
  const result = parseCSV(csv, { lineSeparator: '\r\n' });

  assertEquals(result.rows.length, 2, 'Should have 2 rows');
  assertEquals(result.rows[0].name, 'Alice', 'First name should be Alice');
  assertEquals(result.rows[1].name, 'Bob', 'Second name should be Bob');
});

// ============================================================================
// TYPE COERCION TESTS
// ============================================================================

runTest('Type coercion - numbers as integers', () => {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].age, 'number', 'Age should be number');
  assertEquals(result.rows[0].age, 30, 'Age should be 30');
});

runTest('Type coercion - numbers as floats', () => {
  const csv = 'name,price\nApple,1.99\nBanana,0.50';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].price, 'number', 'Price should be number');
  assertEquals(result.rows[0].price, 1.99, 'Price should be 1.99');
});

runTest('Type coercion - negative numbers', () => {
  const csv = 'item,adjustment\nStock,-50';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].adjustment, 'number', 'Should be number');
  assertEquals(result.rows[0].adjustment, -50, 'Should be -50');
});

runTest('Type coercion - scientific notation', () => {
  const csv = 'value\n1e5';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].value, 'number', 'Should be number');
  assertEquals(result.rows[0].value, 100000, 'Should parse scientific notation');
});

runTest('Type coercion - boolean true (lowercase)', () => {
  const csv = 'name,active\nAlice,true';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].active, 'boolean', 'Should be boolean');
  assertEquals(result.rows[0].active, true, 'Should be true');
});

runTest('Type coercion - boolean true (uppercase)', () => {
  const csv = 'name,active\nAlice,TRUE';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, 'Should be true (case-insensitive)');
});

runTest('Type coercion - boolean false (lowercase)', () => {
  const csv = 'name,active\nAlice,false';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].active, 'boolean', 'Should be boolean');
  assertEquals(result.rows[0].active, false, 'Should be false');
});

runTest('Type coercion - boolean false (uppercase)', () => {
  const csv = 'name,active\nAlice,FALSE';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, false, 'Should be false (case-insensitive)');
});

runTest('Type coercion - null from "null" string', () => {
  const csv = 'name,value\nAlice,null';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, 'Should be null');
});

runTest('Type coercion - null from "NULL" string (uppercase)', () => {
  const csv = 'name,value\nAlice,NULL';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, 'Should be null (case-insensitive)');
});

runTest('Type coercion - null from empty string', () => {
  const csv = 'name,value\nAlice,';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, 'Empty string should be null');
});

runTest('Type coercion - strings stay as strings', () => {
  const csv = 'name,city\nAlice,NewYork\nBob,LosAngeles';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].city, 'string', 'Should be string');
  assertEquals(result.rows[0].city, 'NewYork', 'Should remain as string');
});

runTest('Type coercion - mixed types in same column', () => {
  const csv = 'name,value\nAlice,42\nBob,hello\nCharlie,true\nDiana,';
  const result = parseCSV(csv);

  assertEquals(typeof result.rows[0].value, 'number', 'First should be number');
  assertEquals(typeof result.rows[1].value, 'string', 'Second should be string');
  assertEquals(typeof result.rows[2].value, 'boolean', 'Third should be boolean');
  assertEquals(result.rows[3].value, null, 'Fourth should be null');
});

// ============================================================================
// ERROR HANDLING TESTS
// ============================================================================

runTest('Error handling - unclosed quote', () => {
  const csv = 'name,description\nAlice,"Unclosed quote';
  const result = parseCSV(csv);

  assertEquals(result.errors.length > 0, true, 'Should have error');
  assertEquals(result.errors[0].row, 1, 'Error should be on row 1');
  assertEquals(result.rows.length, 0, 'Should have no valid rows');
});

runTest('Error handling - field count mismatch (too few)', () => {
  const csv = 'name,age,city\nAlice,30';
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, 'Should have one error');
  assertEquals(result.rows.length, 0, 'Should skip malformed row');
});

runTest('Error handling - field count mismatch (too many)', () => {
  const csv = 'name,age\nAlice,30,Extra';
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, 'Should have one error');
  assertEquals(result.rows.length, 0, 'Should skip malformed row');
});

runTest('Error handling - multiple errors collected', () => {
  const csv = 'name,age\nAlice,30,Extra\nBob,"Unclosed\nCharlie,25,Extra';
  const result = parseCSV(csv);

  assertEquals(result.errors.length >= 2, true, 'Should have multiple errors');
});

runTest('Error handling - continue parsing after error', () => {
  const csv = 'name,age\nAlice,30,Extra\nBob,25';
  const result = parseCSV(csv);

  assertEquals(result.rows.length, 1, 'Should have one valid row');
  assertEquals(result.rows[0].name, 'Bob', 'Valid row should be parsed');
});

// ============================================================================
// EMPTY AND EDGE CASE TESTS
// ============================================================================

runTest('Edge case - empty input', () => {
  const result = parseCSV('');

  assertEquals(result.headers.length, 0, 'Should have no headers');
  assertEquals(result.rows.length, 0, 'Should have no rows');
});

runTest('Edge case - only whitespace', () => {
  const result = parseCSV('   \n  \n  ');

  assertEquals(result.rows.length, 0, 'Should have no rows');
});

runTest('Edge case - empty lines in data', () => {
  const csv = 'name,age\nAlice,30\n\nBob,25\n';
  const result = parseCSV(csv);

  assertEquals(result.rows.length, 2, 'Should skip empty lines');
  assertEquals(result.rows[0].name, 'Alice', 'First row should be Alice');
  assertEquals(result.rows[1].name, 'Bob', 'Second row should be Bob');
});

runTest('Edge case - trailing newline', () => {
  const csv = 'name\nAlice\n';
  const result = parseCSV(csv);

  assertEquals(result.rows.length, 1, 'Should have 1 row');
  assertEquals(result.rows[0].name, 'Alice', 'Row should be parsed correctly');
});

runTest('Edge case - very long field value', () => {
  const longValue = 'a'.repeat(10000);
  const csv = `name,text\nAlice,${longValue}`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text.length, 10000, 'Should handle long field');
  assertEquals(result.rows[0].text, longValue, 'Long field should match');
});

runTest('Edge case - special characters in fields', () => {
  const csv = 'name,text\nAlice,"Special: @#$%^&*()"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, 'Special: @#$%^&*()', 'Should preserve special chars');
});

runTest('Edge case - unicode characters', () => {
  const csv = 'name,city\nAlice,北京\nBob,São Paulo\nCharlie,Москва';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].city, '北京', 'Should handle Chinese');
  assertEquals(result.rows[1].city, 'São Paulo', 'Should handle Portuguese');
  assertEquals(result.rows[2].city, 'Москва', 'Should handle Russian');
});

// ============================================================================
// FILTER TESTS
// ============================================================================

runTest('Filter - basic filter by property', () => {
  const csv = 'name,age\nAlice,30\nBob,25\nCharlie,35';
  const result = parseCSV(csv);
  const filtered = result.filter(row => row.age > 25);

  assertEquals(filtered.rows.length, 2, 'Should have 2 filtered rows');
  assertEquals(filtered.rows[0].name, 'Alice', 'First filtered should be Alice');
  assertEquals(filtered.rows[1].name, 'Charlie', 'Second filtered should be Charlie');
});

runTest('Filter - filter with string match', () => {
  const csv = 'name,city\nAlice,New York\nBob,London\nCharlie,New York';
  const result = parseCSV(csv);
  const filtered = result.filter(row => row.city === 'New York');

  assertEquals(filtered.rows.length, 2, 'Should have 2 rows from New York');
});

runTest('Filter - filter all out', () => {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);
  const filtered = result.filter(row => row.age > 100);

  assertEquals(filtered.rows.length, 0, 'Should have no rows');
});

runTest('Filter - filter with boolean', () => {
  const csv = 'name,active\nAlice,true\nBob,false\nCharlie,true';
  const result = parseCSV(csv);
  const filtered = result.filter(row => row.active === true);

  assertEquals(filtered.rows.length, 2, 'Should have 2 active rows');
});

runTest('Filter - multiple filters chained', () => {
  const csv = 'name,age,active\nAlice,30,true\nBob,25,false\nCharlie,35,true\nDiana,28,true';
  const result = parseCSV(csv);
  const filtered = result
    .filter(row => row.active === true)
    .filter(row => row.age > 28);

  assertEquals(filtered.rows.length, 1, 'Should have 1 row matching all criteria');
  assertEquals(filtered.rows[0].name, 'Charlie', 'Should be Charlie');
});

// ============================================================================
// AGGREGATION - SUM TESTS
// ============================================================================

runTest('Sum - sum numeric column', () => {
  const csv = 'item,price\nApple,1.99\nBanana,0.50\nOrange,0.75';
  const result = parseCSV(csv);
  const total = result.sum('price');

  assertEquals(total, 3.24, 'Sum should be 3.24');
});

runTest('Sum - sum with all values', () => {
  const csv = 'name,sales\nAlice,100\nBob,200\nCharlie,150';
  const result = parseCSV(csv);
  const total = result.sum('sales');

  assertEquals(total, 450, 'Sum should be 450');
});

runTest('Sum - sum column with non-numeric values (ignored)', () => {
  const csv = 'name,value\nAlice,100\nBob,N/A\nCharlie,200';
  const result = parseCSV(csv);
  const total = result.sum('value');

  assertEquals(total, 300, 'Sum should be 300 (N/A ignored)');
});

runTest('Sum - sum column with nulls (ignored)', () => {
  const csv = 'name,value\nAlice,100\nBob,\nCharlie,200';
  const result = parseCSV(csv);
  const total = result.sum('value');

  assertEquals(total, 300, 'Sum should be 300 (nulls ignored)');
});

runTest('Sum - empty column', () => {
  const csv = 'name,value\nAlice,\nBob,';
  const result = parseCSV(csv);
  const total = result.sum('value');

  assertEquals(total, 0, 'Sum of empty column should be 0');
});

// ============================================================================
// AGGREGATION - AVERAGE TESTS
// ============================================================================

runTest('Average - average numeric column', () => {
  const csv = 'name,score\nAlice,100\nBob,80\nCharlie,90';
  const result = parseCSV(csv);
  const avg = result.average('score');

  assertEquals(avg, 90, 'Average should be 90');
});

runTest('Average - average with decimals', () => {
  const csv = 'item,price\nA,1.5\nB,2.5\nC,3.0';
  const result = parseCSV(csv);
  const avg = result.average('price');

  assertEquals(avg, 2.333333333333333, 'Average should be ~2.33');
});

runTest('Average - average with non-numeric values (ignored)', () => {
  const csv = 'name,value\nAlice,100\nBob,invalid\nCharlie,200';
  const result = parseCSV(csv);
  const avg = result.average('value');

