/**
 * CSV Parser Library (JavaScript version)
 * A comprehensive CSV parser with support for quoted fields,
 * type coercion, and aggregation operations.
 */

/**
 * Represents the result of parsing a CSV string
 */
class CSVResult {
  constructor(rows, headers, errors = []) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   * Returns a new CSVResult with only matching rows
   */
  filter(predicate) {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum all numeric values in a column
   * Non-numeric values are ignored
   */
  sum(column) {
    let total = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number') {
        total += value;
      }
    }
    return total;
  }

  /**
   * Calculate the average of numeric values in a column
   * Non-numeric values are ignored
   */
  average(column) {
    const values = this.rows
      .map(row => row[column])
      .filter(value => typeof value === 'number');

    if (values.length === 0) return 0;
    return this.sum(column) / values.length;
  }

  /**
   * Count total number of rows
   */
  count() {
    return this.rows.length;
  }

  /**
   * Group rows by unique values in a column
   * Returns a Map where keys are column values and values are arrays of matching rows
   */
  groupBy(column) {
    const groups = new Map();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key).push(row);
    }

    return groups;
  }
}

/**
 * Parse a line of CSV into fields
 * Handles quoted fields and escaped quotes
 */
function parseCSVLine(line, delimiter = ',', quote = '"') {
  const fields = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (inQuotes) {
      if (char === quote) {
        if (nextChar === quote) {
          // Escaped quote (two consecutive quotes)
          currentField += quote;
          i += 2;
        } else {
          // End of quoted field
          inQuotes = false;
          i++;
        }
      } else {
        currentField += char;
        i++;
      }
    } else {
      if (char === quote) {
        // Start of quoted field
        inQuotes = true;
        i++;
      } else if (char === delimiter) {
        // Field delimiter
        fields.push(currentField);
        currentField = '';
        i++;
      } else {
        currentField += char;
        i++;
      }
    }
  }

  // Add the last field
  fields.push(currentField);

  // Check for unclosed quotes
  if (inQuotes) {
    return { fields, error: 'Unclosed quote in line' };
  }

  return { fields };
}

/**
 * Coerce a string value to its appropriate type
 * Handles: numbers, booleans, null, and strings
 */
function coerceType(value) {
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for number
  const num = Number(value);
  if (!isNaN(num) && value.trim() !== '') {
    // Ensure it's actually a valid number string (not just whitespace)
    if (String(num) === String(parseFloat(value))) {
      return num;
    }
  }

  // Return as string
  return value;
}

/**
 * Parse a CSV string into structured data
 * @param {string} input The CSV string to parse
 * @param {object} options Parser configuration
 * @returns {CSVResult} A CSVResult object with rows, headers, errors, and utility methods
 */
function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const errors = [];

  // Handle empty input
  if (!input || input.trim() === '') {
    return new CSVResult([], [], []);
  }

  // Split into lines
  let lines = input.split(lineSeparator);

  // Handle case where input ends with separator
  if (lines[lines.length - 1] === '') {
    lines.pop();
  }

  if (lines.length === 0) {
    return new CSVResult([], [], []);
  }

  // Parse header line
  const headerLine = lines[0];
  const headerResult = parseCSVLine(headerLine, delimiter, quote);

  if (headerResult.error) {
    errors.push({ row: 0, message: headerResult.error });
  }

  const headers = headerResult.fields.map(field => field.trim());

  // Parse data lines
  const rows = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (line.trim() === '') {
      continue;
    }

    const parseResult = parseCSVLine(line, delimiter, quote);

    if (parseResult.error) {
      errors.push({ row: i, message: parseResult.error });
      continue;
    }

    const fields = parseResult.fields;

    // Check if the number of fields matches headers
    if (fields.length !== headers.length) {
      errors.push({
        row: i,
        message: `Expected ${headers.length} fields, got ${fields.length}`,
      });
      continue;
    }

    // Create row object
    const row = {};
    for (let j = 0; j < headers.length; j++) {
      const rawValue = fields[j].trim();
      row[headers[j]] = coerceType(rawValue);
    }

    rows.push(row);
  }

  return new CSVResult(rows, headers, errors);
}

module.exports = { parseCSV, CSVResult };

