### GroupBy with Aggregation

```javascript
const csv = `name,department,salary
Alice,Sales,50000
Bob,Engineering,60000
Charlie,Sales,45000
Diana,Engineering,55000
Eve,Marketing,48000`;

const result = parseCSV(csv);

const byDept = result.groupBy('department');

// Calculate department averages
for (const [dept, employees] of byDept) {
  const salaries = employees.map(e => e.salary).reduce((a, b) => a + b, 0);
  const avgSalary = salaries / employees.length;
  console.log(`${dept}: $${avgSalary.toFixed(2)}`);
