  .filter(row => row.category === 'Fruit')
  .average('rating');
console.log(fruitRating);      // 4.35
```

### Count - Record Statistics

```javascript
const csv = `name,status
Alice,Active
Bob,Inactive
Charlie,Active
Diana,Active
Eve,Inactive`;

const result = parseCSV(csv);

console.log(result.count());               // 5 (total records)

const active = result.filter(row => row.status === 'Active');
console.log(active.count());               // 3 (active records)

const inactive = result.filter(row => row.status === 'Inactive');
console.log(inactive.count());             // 2 (inactive records)
```

### GroupBy - Organization

```javascript
const csv = `name,department,salary
Alice,Sales,50000
Bob,Engineering,60000
Charlie,Sales,45000
Diana,Engineering,55000
Eve,Marketing,48000`;

const result = parseCSV(csv);

const byDept = result.groupBy('department');

// List employees in each department
console.log('Sales:', byDept.get('Sales').map(r => r.name));
// ['Alice', 'Charlie']

console.log('Engineering:', byDept.get('Engineering').map(r => r.name));
// ['Bob', 'Diana']

console.log('Marketing:', byDept.get('Marketing').map(r => r.name));
// ['Eve']
```

### GroupBy with Aggregation

```javascript
const csv = `name,department,salary
Alice,Sales,50000
Bob,Engineering,60000
Charlie,Sales,45000
Diana,Engineering,55000
Eve,Marketing,48000`;

const result = parseCSV(csv);

const byDept = result.groupBy('department');

// Calculate department averages
for (const [dept, employees] of byDept) {
  const salaries = employees.map(e => e.salary).reduce((a, b) => a + b, 0);
  const avgSalary = salaries / employees.length;
  console.log(`${dept}: $${avgSalary.toFixed(2)}`);
}
// Sales: $47500.00
// Engineering: $57500.00
// Marketing: $48000.00
```

### GroupBy with Null Values

```javascript
const csv = `name,category
Alice,A
Bob,
Charlie,A
Diana,B
Eve,`;

const result = parseCSV(csv);

const byCategory = result.groupBy('category');

console.log('Category A:', byCategory.get('A').length);      // 2
console.log('Category B:', byCategory.get('B').length);      // 1
console.log('No Category:', byCategory.get(null).length);    // 2
```

## Real-World Examples

### Sales Report

```javascript
const csv = `date,product,quantity,unitPrice,region
2024-01-15,Product A,10,100.00,North
2024-01-15,Product B,5,50.00,South
2024-01-16,Product A,12,100.00,North
2024-01-16,Product C,8,75.00,East
2024-01-17,Product B,6,50.00,South
2024-01-17,Product A,9,100.00,East`;

const result = parseCSV(csv);

// Total sales
const totalQuantity = result.sum('quantity');
const totalValue = result.rows.reduce((sum, row) => sum + (row.quantity * row.unitPrice), 0);
console.log(`Total items sold: ${totalQuantity}`);
console.log(`Total revenue: $${totalValue.toFixed(2)}`);

// Sales by region
const byRegion = result.groupBy('region');
for (const [region, sales] of byRegion) {
  const regional = sales.reduce((sum, row) => sum + (row.quantity * row.unitPrice), 0);
  console.log(`${region}: $${regional.toFixed(2)}`);
}

// Product performance
const byProduct = result.groupBy('product');
console.log(`\nProduct Performance:`);
for (const [product, sales] of byProduct) {
  const totalSales = sales.reduce((sum, row) => sum + row.quantity, 0);
  const avgPrice = sales.reduce((sum, row) => sum + row.unitPrice, 0) / sales.length;
  console.log(`${product}: ${totalSales} units, avg price $${avgPrice.toFixed(2)}`);
}
```

### Student Grades Analysis

```javascript
const csv = `name,math,english,science,history
Alice,95,87,92,88
Bob,78,82,85,80
Charlie,92,88,90,93
Diana,85,90,88,87
Eve,88,91,86,89`;

const result = parseCSV(csv);

// Class averages
console.log('Subject Averages:');
console.log(`Math: ${result.average('math').toFixed(2)}`);
console.log(`English: ${result.average('english').toFixed(2)}`);
console.log(`Science: ${result.average('science').toFixed(2)}`);
console.log(`History: ${result.average('history').toFixed(2)}`);

// Student averages
console.log('\nStudent Averages:');
result.rows.forEach(row => {
  const avg = (row.math + row.english + row.science + row.history) / 4;
  console.log(`${row.name}: ${avg.toFixed(2)}`);
});

// Top performers (>90 average)
const topStudents = result.rows.filter(row => {
  const avg = (row.math + row.english + row.science + row.history) / 4;
  return avg > 90;
}).map(r => r.name);
console.log(`\nTop Performers: ${topStudents.join(', ')}`);
```

### Inventory Management

```javascript
const csv = `sku,product,quantity,reorderLevel,price
SKU001,Widget A,50,20,9.99
SKU002,Widget B,15,25,14.99
SKU003,Gadget X,8,10,49.99
SKU004,Gadget Y,100,50,99.99
SKU005,Tool Z,12,15,24.99`;

const result = parseCSV(csv);

// Low stock items
const lowStock = result.filter(row => row.quantity < row.reorderLevel);
console.log('Items to Reorder:');
lowStock.rows.forEach(row => {
  console.log(`${row.product} (${row.sku}): ${row.quantity} units (need ${row.reorderLevel})`);
});

// Inventory value
const totalValue = result.rows.reduce((sum, row) => sum + (row.quantity * row.price), 0);
console.log(`\nTotal Inventory Value: $${totalValue.toFixed(2)}`);

// Products by stock status
console.log('\nStock Summary:');
console.log(`In Stock: ${result.filter(r => r.quantity >= r.reorderLevel).count()}`);
console.log(`Low Stock: ${result.filter(r => r.quantity < r.reorderLevel).count()}`);
```

These examples demonstrate the full power and flexibility of the CSV Parser library. It handles everything from simple parsing to complex data analysis and reporting scenarios.

