const csv = 'name,age\nAlice,30\nBob,25';
const result = parseCSV(csv);
console.log(result.rows);
// [{ name: 'Alice', age: 30 }, { name: 'Bob', age: 25 }]
```

### With Quoted Fields
```javascript
const csv = 'name,address\nAlice,"123 Main St, New York"';
const result = parseCSV(csv);
console.log(result.rows[0].address);
// "123 Main St, New York"
```

### Custom Delimiter
```javascript
const csv = 'name;age\nAlice;30';
const result = parseCSV(csv, { delimiter: ';' });
```

### Filtering and Aggregation
```javascript
const result = parseCSV(csv);
const avg = result
  .filter(row => row.active === true)
  .average('salary');
```

### GroupBy and Analysis
```javascript
const groups = result.groupBy('department');
for (const [dept, employees] of groups) {
  console.log(`${dept}: ${employees.length} employees`);
}
```

